CREATE TABLE public.crm_referral_payouts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID NOT NULL REFERENCES public.crm_referral_partners(id) ON DELETE CASCADE, signup_id UUID REFERENCES public.crm_referral_company_signups(id) ON DELETE SET NULL, payout_amount NUMERIC(10,2) NOT NULL, payout_status TEXT NOT NULL DEFAULT 'pending', payout_type public.crm_payout_type NOT NULL, calculation_basis TEXT, approved_by UUID REFERENCES auth.users(id) ON DELETE SET NULL, approved_at TIMESTAMPTZ, paid_at TIMESTAMPTZ, payment_reference TEXT, payment_method TEXT, notes TEXT, metadata JSONB DEFAULT '{}', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE TABLE public.crm_referral_account_credit_ledger (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID NOT NULL REFERENCES public.crm_referral_partners(id) ON DELETE CASCADE, signup_id UUID REFERENCES public.crm_referral_company_signups(id) ON DELETE SET NULL, transaction_type public.crm_credit_transaction_type NOT NULL, amount NUMERIC(10,2) NOT NULL, balance_after NUMERIC(10,2) NOT NULL, description TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE TABLE public.crm_referral_flags (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID REFERENCES public.crm_referral_partners(id) ON DELETE CASCADE, signup_id UUID REFERENCES public.crm_referral_company_signups(id) ON DELETE CASCADE, flag_reason public.crm_flag_reason NOT NULL, flag_details TEXT, severity TEXT DEFAULT 'medium', status TEXT DEFAULT 'open', resolved_by UUID REFERENCES auth.users(id) ON DELETE SET NULL, resolved_at TIMESTAMPTZ, resolution_notes TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE TABLE public.crm_referral_status_history (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID REFERENCES public.crm_referral_partners(id) ON DELETE CASCADE, signup_id UUID REFERENCES public.crm_referral_company_signups(id) ON DELETE CASCADE, entity_type TEXT NOT NULL, old_status TEXT, new_status TEXT NOT NULL, changed_by UUID REFERENCES auth.users(id) ON DELETE SET NULL, change_reason TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());